function Search() {
  const [query, setQuery] = useState();
  const [results, setResults] = useState();

  useEffect(() => {
    fetch('/search?query=' + query).then((data) => {
      setResults(data);
    });
  }, [query]);

  return (
    <div>
      <input
        name="query"
        type="text"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
      />
      <ul>
        {results.map((result) => (
          <li key={result.id}>{result.title}</li>
        ))}
      </ul>
    </div>
  )
}

